class efuAI {
  constructor() {
      this.root = this.config.apiUrl; // ChatGPT API endpoint
      this.aiTalkMode = false;
      this.aiPostExplanation = '';
      this.config = GLOBAL_CONFIG.post_ai;
      this.scoGPTIsRunning = false;
  }

  // 初始化
  init() {
      if (!document.querySelector(".ai-explanation")) return;
      this.scoGPTIsRunning = false;
      this.aiPostExplanation = PAGE_CONFIG.ai_text ? PAGE_CONFIG.ai_text + "" : false;

      if (!this.aiPostExplanation) {
          this.generate();
      } else {
          this.aiShowAnimation(Promise.resolve(this.aiPostExplanation));
      }
      this.AIEngine();
  }

  // 获取标题和内容
  getTitleAndContent() {
      const e = document.getElementById("article-container");
      const t = document.title;
      const n = e.getElementsByTagName("p");
      const i = e.querySelectorAll("h1, h2, h3, h4, h5");
      return (t + " " + Array.from(i).concat(Array.from(n)).map(e => e.innerText.replace(/https?:\/\/[^\s]+/g, "")).join(" ")).slice(0, 1000);
  }

  // 生成摘要
  async generate() {
      this.aiShowAnimation(this.fetch(this.getTitleAndContent()));
  }

  // 获取摘要
  async fetch(content) {
      const messages = [
          { role: "user", content: `假如你是一个文章摘要助手，请为以下内容生成摘要：${content}` }
      ];

      const response = await fetch(this.root, {
          method: "POST",
          headers: {
              "Content-Type": "application/json",
              "Authorization": `Bearer ${this.apiKey}`
          },
          body: JSON.stringify({
              model: "gpt-3.5-turbo", // You can change the model if needed
              messages: messages,
              max_tokens: 150 // Adjust the max tokens as needed
          })
      });

      const data = await response.json();

      if (response.ok) {
          this.aiPostExplanation = data.choices[0].message.content;
          return this.aiPostExplanation;
      } else {
          console.error("Request failed:", data.error.message);
          return data.error.message;
      }
  }

  // 显示动画
  aiShowAnimation(promise, showLoading = false) {
      const explanationElement = document.querySelector(".ai-explanation");
      const tagElement = document.querySelector(".ai-tag");

      if (!explanationElement || this.scoGPTIsRunning) return;

      this.scoGPTIsRunning = true;
      this.cleanSuggestions();
      tagElement.classList.add("loadingAI");
      explanationElement.style.display = "block";
      explanationElement.innerHTML = '生成中...<span class="blinking-cursor"></span>';

      let startTime, currentIndex = 0, isVisible = true;
      const observer = new IntersectionObserver(entries => {
          isVisible = entries[0].isIntersecting;
          if (isVisible) requestAnimationFrame(update);
      }, { threshold: 0 });

      promise.then(result => {
          startTime = performance.now();
          const update = () => {
              if (currentIndex < result.length && isVisible) {
                  const currentTime = performance.now();
                  const elapsedTime = currentTime - startTime;
                  const currentChar = result.slice(currentIndex, currentIndex + 1);
                  const isChinese = /[，。！、？,.!?]/.test(currentChar);
                  const isAlphanumeric = /[a-zA-Z0-9]/.test(currentChar);
                  const delay = isChinese ? 100 * Math.random() + 100 : isAlphanumeric ? 10 : 25;

                  if (elapsedTime >= delay) {
                      explanationElement.innerText = result.slice(0, currentIndex + 1);
                      startTime = currentTime;
                      currentIndex++;

                      if (currentIndex < result.length) {
                          explanationElement.innerHTML = result.slice(0, currentIndex) + '<span class="blinking-cursor"></span>';
                      } else {
                          explanationElement.innerHTML = result;
                          explanationElement.style.display = "block";
                          this.scoGPTIsRunning = false;
                          tagElement.classList.remove("loadingAI");
                          observer.disconnect();
                          showLoading && this.createSuggestions();
                      }
                  }
                  if (isVisible) requestAnimationFrame(update);
              }
          };

          isVisible && requestAnimationFrame(update);
          observer.observe(explanationElement);
      }).catch(error => {
          console.error("检索信息失败：", error);
          explanationElement.innerHTML = "检索信息失败";
          explanationElement.style.display = "block";
          this.scoGPTIsRunning = false;
          tagElement.classList.remove("loadingAI");
          observer.disconnect();
      });
  }

  // AI引擎
  AIEngine() {
      const tagElement = document.querySelector(".ai-tag");
      if (tagElement) {
          tagElement.addEventListener("click", () => {
              if (!this.scoGPTIsRunning) {
                  this.aiTalkMode = true;
                  this.aiShowAnimation(Promise.resolve(this.config.talk), true);
              }
          });
      }
  }

  // 清除建议
  cleanSuggestions() {
      const suggestionsElement = document.querySelector(".ai-suggestions");
      if (suggestionsElement) {
          suggestionsElement.innerHTML = "";
      } else {
          console.error("没有这个元素：'ai-suggestions'");
      }
  }

  // 创建建议
  createSuggestions() {
      if (this.aiTalkMode) {
          this.cleanSuggestions();
          this.createSuggestionItemWithAction("这篇文章讲了什么？", () => {
              this.aiPostExplanation === "" ? this.generate() : this.aiShowAnimation(Promise.resolve(this.aiPostExplanation), true);
          });
          if (this.config.randomPost) {
              this.createSuggestionItemWithAction("带我去看看其他文章", () => toRandomPost());
          }
          this.aiTalkMode = true;
      }
  }

  // 创建建议项
  createSuggestionItemWithAction(text, action) {
      const suggestionsElement = document.querySelector(".ai-suggestions");
      if (!suggestionsElement) {
          console.error("无法找到具有class为ai-suggestions的元素");
          return;
      }
      const item = document.createElement("div");
      item.classList.add("ai-suggestions-item");
      item.textContent = text;
      item.addEventListener("click", action);
      suggestionsElement.appendChild(item);
  }
}

const efu_ai = new efuAI();